void eval_model(const float* results, int length)
{
    const float* y = &example_output[0][0];
    float mse = 0;
    for(int i = 0; i < length; i++)
    {
        mse += (results[i]  - y[i]) * (results[i]  - y[i]);
    }

    mse = mse /length;

    ESP_LOGI(TAG, "Final MSE: %f", mse);

}
int run_model() {
        const uint8_t* mmaped_pointer = model_flash.allocatePointerOnFlash("model");
        if (!mmaped_pointer) {
            ESP_LOGE(TAG, "Could not initialize mmaped pointer");
            return 1;
        }
        uint8_t* psram_model_pointer = model_flash.allocatePointerOnPSRAM(model_flash.GetModelSize());

        ESP_LOGI(TAG, "FREE_HEAP,%u",
                (unsigned)heap_caps_get_free_size(MALLOC_CAP_8BIT));

        ESP_LOGI(TAG, "FREE_PSRAM_HEAP_AFTER_ALLOCATION,%u",
                (unsigned)heap_caps_get_free_size(MALLOC_CAP_SPIRAM));

        // Transfer model from flash to PSRAM
        memcpy(psram_model_pointer, mmaped_pointer, model_flash.GetModelSize());

        benchmark_model = new Model(&model_flash,psram_model_pointer, ARENA_SIZE);
        
        ESP_LOGI(TAG, "MODEL CREATED");
        if (benchmark_model->isInitialized()) {
            ESP_LOGI(TAG, "MODEL INTIALIZED SUCCESSFULLY");
        } else {
             ESP_LOGE(TAG, "Model was not initialized successfully");
            
        }
        // TODO: Fill in input array with something

        float results[2][250] = {0};

        uint64_t startTime = esp_timer_get_time();
        bool success = benchmark_model->predict(
            &example_data[0][0], 8 * 500, &results[0][0], 2 * 250);
        uint64_t duration = esp_timer_get_time() - startTime;

        if (success) {
            ESP_LOGI(TAG, "RES,%lld,%d", duration,
                    benchmark_model->getArenaUsedBytes());
            for (int r = 0; r < 2; r++) {
                printf("Channel %d", r);
                for(int c=0; c < 250; c++)
                {
                    printf(",%0.4f", results[r][c]);
                }
                printf("\n");
            }
            eval_model((const float *)(&results[0][0]), 2 * 250);
            printf("\n");
        } else {
            ESP_LOGE(TAG, "INFERENCE ERROR");
            return 1;
        }
        return 0;
        
}

extern "C" void app_main(void) {
    printf("ESP32_READY\n");
    ESP_LOGW(TAG, "FREE_HEAP_CONT_START,%u",
                (unsigned)heap_caps_get_largest_free_block(MALLOC_CAP_8BIT));
    run_model();
}